import { useState } from 'react'
import { Link as RouterLink } from 'react-router-dom'
import { Link as ScrollLink } from "react-scroll";
import styled from "styled-components";
import Brand from "./Brand";
import hamburger from '../../img/LandingPage/hamburger.svg'

const Nav = () => {
  const [hamburgerState, setHamburgerState] = useState(false)
  
  const handleHamburgerClick = () => {
    setHamburgerState(!hamburgerState)
  }

  return (
    <NavContainer>
      <RouterLink to="/">
        <Brand />
      </RouterLink>

      <div style={{ display: "flex", alignItems: "center", columnGap: "5em" }}>
        {hamburgerState &&
          <NavLinks>
            <li>
              <ScrollLink to="About" smooth={true} duration={500} onClick={() => setHamburgerState(false)}>
                About
              </ScrollLink>
            </li>
          </NavLinks>
        }
        
        <Hamburger active={hamburgerState} onClick={handleHamburgerClick}>
          <span /> <span /> <span />
          {/* <img src={hamburger} alt="show categories" /> */}
        </Hamburger>
      </div>
    </NavContainer>
  )
}

const NavContainer = styled.nav`
  grid-column: 1/3;
  display: flex;
  justify-content: space-between;
  padding: 2em;

  position: sticky;

  & img {
    filter: invert(1);
    width: 2em;
    height: 2em;
  }
`

const Hamburger = styled.button`
  background: transparent;
  border: 0;
  cursor: pointer;
  width: 3em;
  height: 2em;

  position: relative;

  & > span {
    left: 0;
    display: block;
    width: 100%;
    height: 3px;
    position: absolute;
    
    background: white;
    border-radius: 3px;

    transition: 0.2s;

    &:first-of-type {
      top: 0%;
      ${props => props.active && "transform: rotate(-45deg) translateY(20px)"}
    }

    &:nth-of-type(2) {
      top: 50%;
      ${props => props.active && "opacity: 0"}
    }

    &:last-of-type {
      top: 100%;
      ${props => props.active && "transform: rotate(45deg)"}
    }
  }
`

const NavLinks = styled.ul`
  padding: 0;
  margin: 0;
`

export default Nav
